(function(){
  function writeScript(src){
    document.write('<script src="'+src+'"><\/script>');
  }
  if(typeof wet==='undefined'||!wet.builder){
    writeScript('/scripts/cdts/soyutils.js');
    var lang=(document.documentElement&&document.documentElement.lang||'en').toLowerCase();
    writeScript('/scripts/cdts/'+(lang==='fr'?'wet-fr.js':'wet-en.js'));
  }
  document.write(wet.builder.refTop({isApplication:!0}));
})();